# ------------------------------------------------------------------
# Graph nodes
# ------------------------------------------------------------------
def _nodes() -> list:
    return [
        helper.make_node('Conv', inputs=['model_input', 'n0_sal_w', 'n0_sal_b'], outputs=['n0_sal_cv'], kernel_shape=[1, 1], pads=[0, 0, 0, 0]),
        helper.make_node('Relu', inputs=['n0_sal_cv'], outputs=['n0_sal_rl']),
        helper.make_node('Softmax', inputs=['n0_sal_rl'], outputs=['n0_sal_out'], axis=1),
        helper.make_node('Pad', inputs=['n0_sal_out', 'n100_rfpcv_pads'], outputs=['n100_rfpcv_pad'], mode='reflect'),
        helper.make_node('Conv', inputs=['n100_rfpcv_pad', 'n100_rfpcv_w', 'n100_rfpcv_b'], outputs=['n100_rfpcv_out'], kernel_shape=[3, 3], pads=[0, 0, 0, 0], strides=[1, 1]),
        helper.make_node('Abs', inputs=['n100_rfpcv_out'], outputs=['n200_logclamp_abs']),
        helper.make_node('Add', inputs=['n200_logclamp_abs', 'n200_logclamp_eps'], outputs=['n200_logclamp_add']),
        helper.make_node('Log', inputs=['n200_logclamp_add'], outputs=['n200_logclamp_log']),
        helper.make_node('Clip', inputs=['n200_logclamp_log', 'n200_logclamp_min', 'n200_logclamp_max'], outputs=['n200_logclamp_out']),
        helper.make_node('Abs', inputs=['n200_logclamp_out'], outputs=['n300_pwc_abs']),
        helper.make_node('Add', inputs=['n300_pwc_abs', 'n300_pwc_eps'], outputs=['n300_pwc_add']),
        helper.make_node('Pow', inputs=['n300_pwc_add', 'n300_pwc_two'], outputs=['n300_pwc_sq']),
        helper.make_node('Sqrt', inputs=['n300_pwc_sq'], outputs=['n300_pwc_out']),
        helper.make_node('ReduceMax', inputs=['n300_pwc_out'], outputs=['n400_redu_red'], axes=[-1], keepdims=1),
        helper.make_node('Mul', inputs=['n300_pwc_out', 'n400_redu_zero'], outputs=['n400_redu_z']),
        helper.make_node('Add', inputs=['n400_redu_z', 'n400_redu_red'], outputs=['n400_redu_out']),
    ]

# ------------------------------------------------------------------
# Model builder
# ------------------------------------------------------------------
def build_model() -> bytes:
    inputs_info  = [helper.make_tensor_value_info(INPUT_NAME, TensorProto.FLOAT, INPUT_SHAPE)]
    outputs_info = [helper.make_tensor_value_info(OUTPUT_NAME, TensorProto.FLOAT, OUTPUT_SHAPE)]
    graph = helper.make_graph(_nodes(), "bug_000350", inputs_info, outputs_info, initializer=_inits())
    model = helper.make_model(graph, opset_imports=[helper.make_opsetid("", OPSET)])
    model.ir_version = IR_VERSION
    return model.SerializeToString()


